import 'package:flutter/material.dart';import '../../services/sync_plan_service.dart';import '../../state/settings_controller.dart';class SyncPlanPage extends StatelessWidget{const SyncPlanPage({super.key,required this.settingsController});final SettingsController settingsController;@override Widget build(BuildContext context){final plan=SyncPlanService().buildPlan(localHashes:const {'devices.json':'local-a','settings.json':'same'},remoteHashes:const {'settings.json':'same','manifest.json':'remote-b','devices.json':'remote-a'});return Scaffold(appBar:AppBar(title:const Text('Sync Plan')),body:ListView(padding:const EdgeInsets.all(16),children:[Card(child:ListTile(leading:Icon(plan.requiresUserDecision?Icons.warning_amber_outlined:Icons.check_circle_outline),title:Text(plan.requiresUserDecision?'User decision required':'Plan ready'),subtitle:Text('Uploads: ${plan.uploads.length} · Downloads: ${plan.downloads.length} · Conflicts: ${plan.conflicts.length}'))),const SizedBox(height:12),...plan.conflicts.map((c)=>Card(child:ListTile(leading:Icon(c.needsUserDecision?Icons.report_problem_outlined:Icons.compare_arrows_outlined),title:Text(c.path),subtitle:Text('${c.type.name} · local=${c.localHash ?? '-'} · remote=${c.remoteHash ?? '-'}'))))]));}}
